using System; using System.Collections.Generic; using System.Linq; using StargateGalacticCommand.Core.Models;
namespace StargateGalacticCommand.Core.Services { public class AllianceService { public Alliance CreateAlliance(User founder,string name,string tag,string description,DateTime now){ if(founder==null)throw new ArgumentNullException("founder"); name=(name??"").Trim(); tag=(tag??"").Trim().ToUpperInvariant(); if(name.Length<3||name.Length>80)throw new ArgumentException("Allianzname muss 3 bis 80 Zeichen haben."); if(tag.Length<2||tag.Length>8)throw new ArgumentException("Allianz-Tag muss 2 bis 8 Zeichen haben."); var a=new Alliance{Name=name,Tag=tag,Description=(description??"").Trim(),FounderUserId=founder.Id,FounderUser=founder,CreatedAtUtc=now}; a.Members.Add(new AllianceMember{Alliance=a,UserId=founder.Id,User=founder,Rank=AllianceRank.Founder,JoinedAtUtc=now}); return a;} public AllianceApplication Apply(Alliance alliance,User user,string message,IEnumerable<AllianceMember> memberships,IEnumerable<AllianceApplication> applications,DateTime now){ if(alliance==null||user==null)throw new ArgumentNullException(); if(memberships!=null&&memberships.Any(m=>m.UserId==user.Id))throw new InvalidOperationException("Spieler ist bereits in einer Allianz."); if(applications!=null&&applications.Any(a=>a.UserId==user.Id&&a.AllianceId==alliance.Id&&a.IsOpen))throw new InvalidOperationException("Offene Bewerbung existiert bereits."); return new AllianceApplication{AllianceId=alliance.Id,Alliance=alliance,UserId=user.Id,User=user,Message=(message??"").Trim(),CreatedAtUtc=now};} public AllianceMember Accept(AllianceApplication app,User actor,IEnumerable<AllianceMember> members,DateTime now){ if(app==null||actor==null)throw new ArgumentNullException(); var rank=members.SingleOrDefault(m=>m.UserId==actor.Id&&m.AllianceId==app.AllianceId)?.Rank; if(rank!=AllianceRank.Founder&&rank!=AllianceRank.Officer)throw new InvalidOperationException("Nur Gründer oder Offiziere können Bewerbungen annehmen."); if(!app.IsOpen)throw new InvalidOperationException("Bewerbung ist nicht offen."); app.AcceptedAtUtc=now; app.DecidedByUserId=actor.Id; return new AllianceMember{AllianceId=app.AllianceId,UserId=app.UserId,Rank=AllianceRank.Member,JoinedAtUtc=now};} } }
